{{#hideDiscussions}}
a[href="/discussions"], li:has(> a[href="/discussions"]) { display: none !important; }
{{/hideDiscussions}}
{{#hideCodespaces}}
a[href="/codespaces"], li:has(> a[href="/codespaces"]) { display: none !important; }
{{/hideCodespaces}}
{{#hideExplore}}
a[href="/explore"], li:has(> a[href="/explore"]) { display: none !important; }
{{/hideExplore}}
{{#hideMarketplace}}
a[href="/marketplace"], li:has(> a[href="/marketplace"]) { display: none !important; }
{{/hideMarketplace}}
{{#hideMcp}}
a[href="/mcp"], li:has(> a[href="/mcp"]) { display: none !important; }
{{/hideMcp}}
{{#hideCopilot}}
a[href="/copilot"]:not(#__billiax-toolbar a), li:has(> a[href="/copilot"]) { display: none !important; }
{{/hideCopilot}}
{{#expandSidebarRepos}}
.AppHeader nav [class*="ActionList"] li:nth-child(n+6):not(:last-child) { display: list-item !important; }
{{/expandSidebarRepos}}

/* Collapse empty menu separators and sections */
dialog nav > ul > li:empty { display: none !important; }
dialog nav > ul > li:has(> ul:empty) { display: none !important; }
dialog nav > ul > li[class*="ActionList-sectionDivider"]:has(+ li:empty),
dialog nav > ul > li[class*="ActionList-sectionDivider"]:has(+ li > ul:empty) { display: none !important; }
dialog nav > ul > li:not(:has(a:not([style*="display: none"]))) { margin: 0 !important; padding: 0 !important; min-height: 0 !important; height: 0 !important; overflow: hidden !important; }
